import { useNavigate } from 'react-router-dom';
import CustomButton from '../components/CustomButton';
import CustomCarousel from '../components/CustomCarousel';
import MultiCardVideoContainer from "../components/MultiCardVideoContainer";
import { images_sparkle, videos_sparkle, videos_creamyland, videos_leveldesign, videos_switch } from '../constants';
import "../styles/Home.css";
import CustomCard from '../components/CustomCard';
import CustomSection from '../components/CustomSection';

function GameButton() {
    const navigate = useNavigate();
  
    return (
      <>
        <CustomButton
          buttonLabel={"game"}
          onClick={() => navigate('/game')}
        />
      </>
    );
  }

  function Home(){
    
    return <div className='home'>
    {/*<CustomCard content={<CustomSection content={<CustomCarousel images={images_sparkle} />} />} />*/}

    <MultiCardVideoContainer videos={videos_sparkle} />
    <GameButton/>
    </div>
  }

  export default Home;
